from __future__ import annotations

from dataclasses import asdict

from .models import Organization


def organization_to_response(organization: Organization) -> dict:
    return asdict(organization)


def organization_collection_to_response(organizations: list[Organization]) -> dict:
    return {"items": [organization_to_response(item) for item in organizations]}

from __future__ import annotations

from typing import Protocol

from .models import Organization


class OrganizationRepository(Protocol):
    def list_organizations(self) -> list[Organization]:
        ...

    def get_organization(self, organization_id: int) -> Organization | None:
        ...


class InMemoryOrganizationRepository:
    def __init__(self, organizations: list[Organization] | None = None):
        self._organizations = organizations or []

    def list_organizations(self) -> list[Organization]:
        return list(self._organizations)

    def get_organization(self, organization_id: int) -> Organization | None:
        for organization in self._organizations:
            if organization.organization_id == organization_id:
                return organization
        return None

from __future__ import annotations

from .models import Organization
from .repositories import OrganizationRepository


class OrganizationService:
    def __init__(self, repository: OrganizationRepository):
        self._repository = repository

    def list_organizations(self) -> list[Organization]:
        return self._repository.list_organizations()

    def get_organization(self, organization_id: int) -> Organization | None:
        return self._repository.get_organization(organization_id)

from __future__ import annotations

from .schemas import organization_collection_to_response, organization_to_response
from .services import OrganizationService

API_PATH_CCORE_ORGANIZATIONS = "/api/ccore/organizations"


def list_organizations(service: OrganizationService) -> dict:
    return organization_collection_to_response(service.list_organizations())


def get_organization(service: OrganizationService, organization_id: int) -> dict:
    organization = service.get_organization(organization_id)
    if organization is None:
        return {"error": "CCORE_ORGANIZATION_NOT_FOUND"}
    return organization_to_response(organization)

const ORGANIZATIONS_ENDPOINT = "/api/ccore/organizations";

async function loadOrganizations() {
    const statusElement = document.getElementById("organizations-status");
    const tableBody = document.querySelector("#organizations-table tbody");

    try {
        const response = await fetch(ORGANIZATIONS_ENDPOINT);
        const payload = await response.json();
        const items = payload.items || [];

        tableBody.innerHTML = items.map((organization) => `
            <tr data-organization-id="${organization.organization_id}">
                <td>${organization.organization_name || ""}</td>
                <td>${organization.organization_code || ""}</td>
                <td>${organization.organization_type_name || ""}</td>
                <td>${organization.is_active ? "Yes" : "No"}</td>
                <td>${organization.updated_at || ""}</td>
            </tr>
        `).join("");

        statusElement.textContent = `${items.length} organization(s) loaded.`;
    } catch (error) {
        statusElement.textContent = "Could not load organizations.";
    }
}

document.addEventListener("DOMContentLoaded", loadOrganizations);

.ccore-organizations-page {
    max-width: 1100px;
    margin: 0 auto;
    padding: 24px;
}

#organizations-table {
    width: 100%;
    border-collapse: collapse;
}

#organizations-table th,
#organizations-table td {
    padding: 8px 10px;
    text-align: left;
    border-bottom: 1px solid #ddd;
}
